+/** URL-safe slug: lowercase, diacritics stripped, non-alnum collapsed to '-', trimmed. */
+export function slugify(input: string): string {
+  return input
+    .normalize('NFKD')
+    .replace(/[\u0300-\u036f]/g, '')
+    .toLowerCase()
+    .replace(/[^a-z0-9]+/g, '-')
+    .replace(/^-+|-+$/g, '');
+}
diff --git a/src/util/slugify.test.ts b/src/util/slugify.test.ts
+import { slugify } from './slugify';
+test('spaces become single hyphen', () => expect(slugify('Hello World')).toBe('hello-world'));
+test('punctuation collapses', () => expect(slugify('a -- b!!c')).toBe('a-b-c'));
+test('strips accents', () => expect(slugify('Crème Brûlée')).toBe('creme-brulee'));
